**Blog Layout (with sidebar):**

```tsx
// app/blog/layout.tsx
export default function BlogLayout({ children }) {
  const categories = ['React', 'Next.js', 'TypeScript', 'JavaScript'];
  const recentPosts = [
    { slug: 'getting-started-nextjs', title: 'Getting Started with Next.js' },
    { slug: 'react-hooks-guide', title: 'React Hooks Guide' },
    { slug: 'typescript-basics', title: 'TypeScript Basics' },
  ];

  return (
    <div className="blog-layout container">
      <div className="blog-content">
        {children}
      </div>

      <aside className="blog-sidebar">
        <div className="sidebar-section">
          <h3>Recent Posts</h3>
          <ul>
            {recentPosts.map(post => (
              <li key={post.slug}>
                <a href={`/blog/${post.slug}`}>{post.title}</a>
              </li>
            ))}
          </ul>
        </div>

        <div className="sidebar-section">
          <h3>Categories</h3>
          <ul>
            {categories.map(category => (
              <li key={category}>
                <a href={`/blog?category=${category}`}>{category}</a>
              </li>
            ))}
          </ul>
        </div>
      </aside>
    </div>
  );
}
```

**Blog List Page:**

```tsx
// app/blog/page.tsx
export const metadata = {
  title: 'Blog',
  description: 'Read my latest articles',
};

async function getPosts() {
  // In real app, fetch from database or CMS
  return [
    {
      slug: 'getting-started-nextjs',
      title: 'Getting Started with Next.js',
      excerpt: 'Learn the basics of Next.js',
      date: '2024-01-15',
    },
    {
      slug: 'react-hooks-guide',
      title: 'Complete React Hooks Guide',
      excerpt: 'Master React hooks',
      date: '2024-01-20',
    },
  ];
}

export default async function BlogPage() {
  const posts = await getPosts();

  return (
    <div>
      <h1>Blog</h1>
      <div className="posts-grid">
        {posts.map(post => (
          <article key={post.slug} className="post-card">
            <h2>
              <a href={`/blog/${post.slug}`}>{post.title}</a>
            </h2>
            <p className="date">{post.date}</p>
            <p>{post.excerpt}</p>
            <a href={`/blog/${post.slug}`} className="read-more">
              Read more →
            </a>
          </article>
        ))}
      </div>
    </div>
  );
}
```

**Individual Blog Post (Dynamic Route):**

```tsx
// app/blog/[slug]/page.tsx

// Generate metadata dynamically
export async function generateMetadata({ params }) {
  const post = await getPost(params.slug);

  return {
    title: post.title,
    description: post.excerpt,
  };
}

async function getPost(slug) {
  // In real app, fetch from database/CMS
  const posts = {
    'getting-started-nextjs': {
      title: 'Getting Started with Next.js',
      content: 'Next.js is a React framework...',
      date: '2024-01-15',
      author: 'John Doe',
    },
  };

  return posts[slug];
}

export default async function BlogPost({ params }) {
  const post = await getPost(params.slug);

  if (!post) {
    return <div>Post not found</div>;
  }

  return (
    <article className="blog-post">
      <header>
        <h1>{post.title}</h1>
        <div className="meta">
          <span>By {post.author}</span>
          <span>{post.date}</span>
        </div>
      </header>

      <div className="content">
        <p>{post.content}</p>
      </div>
    </article>
  );
}
```

**Routes created:**
- `/` → Home page
- `/about` → About page
- `/blog` → Blog list (with sidebar)
- `/blog/getting-started-nextjs` → Blog post (with sidebar)
- `/blog/react-hooks-guide` → Blog post (with sidebar)

**Key features:**
✅ Root layout with header/footer on all pages
✅ Nested blog layout with sidebar only on blog pages
✅ Dynamic routes for individual posts
✅ Server-side data fetching
✅ Dynamic metadata for SEO
✅ Clean URL structure
